'use client'

import { useEffect, useRef } from 'react'
import { gsap } from 'gsap'
import { ScrollTrigger } from 'gsap/ScrollTrigger'

gsap.registerPlugin(ScrollTrigger)

export default function InstagramSection() {
  const titleRef = useRef<HTMLHeadingElement>(null)
  const postsRef = useRef<(HTMLDivElement | null)[]>([])

  useEffect(() => {
    gsap.fromTo(
      titleRef.current,
      { opacity: 0, y: 30 },
      {
        opacity: 1,
        y: 0,
        duration: 1,
        scrollTrigger: {
          trigger: titleRef.current,
          start: 'top 80%',
        }
      }
    )

    postsRef.current.forEach((post, index) => {
      gsap.fromTo(
        post,
        { opacity: 0, scale: 0.8 },
        {
          opacity: 1,
          scale: 1,
          duration: 0.8,
          delay: index * 0.1,
          scrollTrigger: {
            trigger: post,
            start: 'top 85%',
          }
        }
      )
    })
  }, [])

  return (
    <section className="py-32 px-8 bg-preto text-branco">
      <div className="max-w-[1400px] mx-auto">
        <div className="text-center mb-12">
          <h2 
            ref={titleRef}
            className="font-display text-branco font-medium mb-4"
            style={{ fontSize: 'clamp(2.5rem, 5vw, 3.5rem)' }}
          >
            Follow Our Journey
          </h2>
          <p className="text-inox text-lg tracking-wider">@babeldesigns</p>
        </div>

        {/* Instagram Grid */}
        <div className="grid grid-cols-2 md:grid-cols-3 gap-4 mb-12">
          {[...Array(6)].map((_, index) => (
            <div
              key={index}
              ref={(el) => { postsRef.current[index] = el }}
              className="aspect-square bg-cinza relative overflow-hidden cursor-pointer group"
            >
              <div className="absolute inset-0 bg-preto/50 opacity-0 group-hover:opacity-100 transition-opacity duration-300 flex items-center justify-center">
                <svg className="w-12 h-12 text-branco transform scale-0 group-hover:scale-100 transition-transform duration-300" fill="currentColor" viewBox="0 0 24 24">
                  <path d="M12 2.163c3.204 0 3.584.012 4.85.07 3.252.148 4.771 1.691 4.919 4.919.058 1.265.069 1.645.069 4.849 0 3.205-.012 3.584-.069 4.849-.149 3.225-1.664 4.771-4.919 4.919-1.266.058-1.644.07-4.85.07-3.204 0-3.584-.012-4.849-.07-3.26-.149-4.771-1.699-4.919-4.92-.058-1.265-.07-1.644-.07-4.849 0-3.204.013-3.583.07-4.849.149-3.227 1.664-4.771 4.919-4.919 1.266-.057 1.645-.069 4.849-.069zm0-2.163c-3.259 0-3.667.014-4.947.072-4.358.2-6.78 2.618-6.98 6.98-.059 1.281-.073 1.689-.073 4.948 0 3.259.014 3.668.072 4.948.2 4.358 2.618 6.78 6.98 6.98 1.281.058 1.689.072 4.948.072 3.259 0 3.668-.014 4.948-.072 4.354-.2 6.782-2.618 6.979-6.98.059-1.28.073-1.689.073-4.948 0-3.259-.014-3.667-.072-4.947-.196-4.354-2.617-6.78-6.979-6.98-1.281-.059-1.69-.073-4.949-.073zm0 5.838c-3.403 0-6.162 2.759-6.162 6.162s2.759 6.163 6.162 6.163 6.162-2.759 6.162-6.163c0-3.403-2.759-6.162-6.162-6.162zm0 10.162c-2.209 0-4-1.79-4-4 0-2.209 1.791-4 4-4s4 1.791 4 4c0 2.21-1.791 4-4 4zm6.406-11.845c-.796 0-1.441.645-1.441 1.44s.645 1.44 1.441 1.44c.795 0 1.439-.645 1.439-1.44s-.644-1.44-1.439-1.44z"/>
                </svg>
              </div>
            </div>
          ))}
        </div>

        <div className="text-center">
          <a 
            href="https://instagram.com/babeldesigns" 
            target="_blank" 
            rel="noopener noreferrer"
            className="inline-block px-12 py-5 bg-transparent text-branco border-2 border-branco text-sm tracking-[0.2em] uppercase font-medium hover:bg-branco hover:text-preto transition-all duration-400 hover:-translate-y-2"
          >
            Follow @babeldesigns
          </a>
        </div>
      </div>
    </section>
  )
}