'use client'

import { useEffect, useRef } from 'react'
import { gsap } from 'gsap'
import { ScrollTrigger } from 'gsap/ScrollTrigger'
import Link from 'next/link'

gsap.registerPlugin(ScrollTrigger)

export default function CTASection() {
  const titleRef = useRef<HTMLHeadingElement>(null)
  const buttonRef = useRef<HTMLAnchorElement>(null)

  useEffect(() => {
    gsap.fromTo(
      titleRef.current,
      { opacity: 0, y: 30 },
      {
        opacity: 1,
        y: 0,
        duration: 1,
        scrollTrigger: {
          trigger: titleRef.current,
          start: 'top 80%',
        }
      }
    )

    gsap.fromTo(
      buttonRef.current,
      { opacity: 0, y: 20 },
      {
        opacity: 1,
        y: 0,
        duration: 1,
        delay: 0.3,
        scrollTrigger: {
          trigger: buttonRef.current,
          start: 'top 80%',
        }
      }
    )
  }, [])

  return (
    <section className="py-32 px-8 bg-branco text-center">
      <div className="max-w-[1200px] mx-auto">
        <h2 
          ref={titleRef}
          className="font-display text-preto font-medium mb-12"
          style={{ fontSize: 'clamp(2.5rem, 5vw, 5rem)', letterSpacing: '-0.01em' }}
        >
          Ready to Begin?
        </h2>
        <Link 
          ref={buttonRef}
          href="/consultancy"
          className="inline-block px-16 py-6 bg-cinza text-branco border-2 border-cinza text-sm tracking-[0.2em] uppercase font-medium hover:bg-transparent hover:text-cinza transition-all duration-400 hover:-translate-y-2 hover:shadow-2xl"
        >
          Book a Consultation
        </Link>
      </div>
    </section>
  )
}